    static void vector(const FromTypeVector & vec_from, ToTypeVector & vec_to, const DateLUTImpl & time_zone, const Transform & transform,
        [[maybe_unused]] ColumnUInt8::Container * vec_null_map_to, size_t input_rows_count)
